'use strict';(function(){const indexCfg={cache:true};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','section'],};const index=FlexSearch.create('balance',indexCfg);window.bookSearchIndex=index;index.add({'id':0,'href':'/note/debian/packages/','title':"Packages",'section':"Debian",'content':"Packages #  Frequently used packages\n   Name Description     bridge-utils Utilities for configuring the Linux Ethernet bridge   dnsutils Clients provided with BIND   htop interactive processes viewer   hwinfo Hardware identification system    "});index.add({'id':1,'href':'/note/debian/','title':"Debian",'section':"Notes",'content':"Debian notes #  "});index.add({'id':2,'href':'/note/debian/dell-xps-15-9560/','title':"Dell XPS 15 9560",'section':"Debian",'content':"Installer missing non-free wifi firmware #  The Intel 8265/8275 requires non-free firmware whoever this can be added to the installation media.\nCopy the non-free firmware-iwlwifi_*_all.deb from https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/ to firmware folder of the installation media.\nACPI issue #  There is currently a bug that means that some kernels (particularly newer ones) will detect the wrong ACPI revision.\nAdd acpi_rev_override=5 to /etc/default/grub\nGRUB_CMDLINE_LINUX=\u0026#34;acpi_rev_override=5 quiet\u0026#34; Update grub\nupdate-grub Reference #     Name Link     Debian XPS 15 9560 https://wiki.debian.org/InstallingDebianOn/Dell/Dell_XPS_15_9560   Non-free firmware https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/    "});})();